import{_ as t,o,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"31. Notice Of Termination","description":"","frontmatter":{"title":"31. Notice Of Termination","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["employment","termination","preliminary"]},"headers":[],"relativePath":"ebas/mspp/employment/31-notice-of-termination.md","filePath":"ebas/mspp/employment/31-notice-of-termination.md"}'),a={name:"ebas/mspp/employment/31-notice-of-termination.md"};function r(s,e,p,m,l,c){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_31-notice-of-termination" tabindex="-1">31. Notice Of Termination <a class="header-anchor" href="#_31-notice-of-termination" aria-label="Permalink to &quot;31. Notice Of Termination&quot;">​</a></h1><p><strong>31.1</strong> Notice Of Termination By Employer</p><p><strong>a.</strong> In order to terminate the employment of an Employee the Employer must give to the Employee 4 weeks&#39; notice of termination.</p><p><strong>b.</strong> In addition to the notice in 31.1a, Employees over 45 years of age at the time of the giving of the notice with not less than two years&#39; continuous service, are entitled to an additional week’s notice.</p><p><strong>c.</strong> Payment in lieu of the prescribed notice in 31.1a and 31.1b must be made if the appropriate notice period is not required to be worked. Provided that employment may be terminated by the Employee working part of the required period of notice and by the Employer making payment for the remainder of the period of notice.</p><p><strong>d.</strong> The required amount of payment in lieu of notice must equal or exceed the total of all amounts that, if the Employee’s employment had continued until the end of the required period of notice, the Employer would have become liable to pay to the Employee because of the employment continuing during that period. That total must be calculated on the basis of:</p><p><strong>(i)</strong> the Employee’s ordinary hours of work (even if not standard hours); and</p><p><strong>(ii)</strong> the amounts ordinarily payable to the Employee in respect of those hours including (for example) allowances, loading and penalties; and any other amounts payable under the Employee’s contract of employment.</p><p><strong>e.</strong> The Period Of Notice in this clause does not apply:</p><p><strong>(i)</strong> in the case of dismissal for serious misconduct;</p><p><strong>(ii)</strong> to Employees engaged for a specific period of time or for a specific task or tasks;</p><p><strong>(iii)</strong> to Casual and Locum Employees;</p><p><strong>f.</strong> Continuous Service is defined in <a href="/eba/ebas/mspp/leave/67-long-service-leave.html">clause 67</a> (Long Service Leave).</p><p><strong>31.2</strong> Notice Of Termination By An Employee</p><p><strong>a.</strong> The notice of termination required to be given by an Employee is the same as that required of an employer, save and except that there is no requirement on the Employee to give additional notice based on the age of the Employee concerned.</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>b.</strong> If an Employee fails to give the notice specified in clause 31.2a the Employer has the right to withhold monies due to the Employee to a maximum amount equal to the amount the Employee would have received under clause 31.1d.</p><p><strong>31.3</strong> Job Search Entitlement Where an Employer has given notice of termination to an Employee, an Employee shall be allowed up to one day’s time off without loss of pay for the purpose of seeking other employment. The time off shall be taken at times that are convenient to the Employee after consultation with the Employer.</p><p>Plain language terms: notice period, resignation notice, dismissal notice.</p>',19)])])}const f=t(a,[["render",r]]);export{d as __pageData,f as default};
